struct ContentView: View {
    @State private var showPasswordReset = false
    @State private var resetToken: String?

    var body: some View {
        NavigationView {
            VStack {
                Text("Welcome to My App")
                    .font(.largeTitle)
                    .padding()

                Text("This is the main app content.")
                    .padding()

                if let token = resetToken {
                    NavigationLink(
                        destination: PasswordResetView(token: token),
                        isActive: $showPasswordReset
                    ) {
                        EmptyView()
                    }
                    .hidden()
                }
            }
            .onOpenURL { url in
                handleUniversalLink(url: url)
            }
            .onChange(of: resetToken) { newToken in
                if newToken != nil {
                    showPasswordReset = true
                }
            }
        }
    }

    private func handleUniversalLink(url: URL) {
        // Example Universal Link: https://myapp.com/reset-password?token=abc123def456
        guard url.scheme == "https",
              url.host == "myapp.com",
              url.pathComponents.contains("reset-password") else {
            print("Not a recognized universal link for password reset: \(url)")
            return
        }

        let components = URLComponents(url: url, resolvingAgainstBaseURL: false)
        if let tokenItem = components?.queryItems?.first(where: { $0.name == "token" }),
           let token = tokenItem.value {
            print("Received password reset token: \(token)")
            self.resetToken = token
        } else {
            print("Password reset link missing token: \(url)")
        }
    }
}

